package jetbrains.mps.baseLanguage.unitTest.execution.client;

/*Generated by MPS */

import com.intellij.execution.process.ProcessListener;
import jetbrains.mps.baselanguage.unitTest.execution.TestEventMessage;
import org.jetbrains.annotations.NotNull;
import com.intellij.execution.process.ProcessEvent;
import jetbrains.mps.baselanguage.unitTest.execution.launcher.DefaultTestExecutor;
import com.intellij.openapi.util.Key;
import com.intellij.execution.process.ProcessOutputTypes;
import jetbrains.mps.baselanguage.unitTest.execution.TestRawEvent;

/**
 * Listener for an output of a Process, that parses TestEvent tokens in process's output stream and update {@link jetbrains.mps.baseLanguage.unitTest.execution.client.TestRunState} .
 * Works in conjunction with {@code DefaultTestExecutionListener} , the one that embellish output stream with indicators of test start/finish/failure
 * You likely don't need this one unless there's {@link jetbrains.mps.baseLanguage.unitTest.execution.client.TestRunState} you'd like to refresh.
 */
public final class UnitTestProcessListener implements ProcessListener {
  private final Object myToken = new Object();
  private final TestRunState myState;
  private TestEventMessage myLastEvent;
  private StringBuilder myLastText = new StringBuilder();

  public UnitTestProcessListener(@NotNull TestRunState runState) {
    myState = runState;
  }

  @Override
  public void startNotified(@NotNull ProcessEvent event) {
    synchronized (myToken) {
      myState.onStartNotified();
    }
  }

  @Override
  public void processTerminated(@NotNull ProcessEvent event) {
    synchronized (myToken) {
      myState.onTermination(event.getExitCode() == DefaultTestExecutor.EXIT_CODE_FOR_EXCEPTION);
    }
  }

  @Override
  public void onTextAvailable(@NotNull ProcessEvent event, @NotNull Key outputKind) {
    synchronized (myToken) {
      String text = event.getText();
      if (text == null) {
        return;
      }
      myLastText.append(text);
      if (!(text.endsWith("\n"))) {
        return;
      }

      String line = myLastText.toString();
      myLastText = new StringBuilder();
      TestEventMessage testEvent = TestEventMessage.parse(line.trim());
      if (testEvent != null) {
        // event happened
        myLastEvent = testEvent;
        onTestEvent(testEvent);
      } else {
        // just text came
        if (isErrorOutputInProgress()) {
          // FIXME this code dates back to initial 2011 commit with no clear explanation what's the reason. 
          //      I suspect this is more of a confusion where DefaultRunListener used to write stacktrace to stderr in testFailure()/testAsssumptionFailure()
          //      while CommandOutputStream has been attached to stdout!
          //      In fact, CommandOutputStream/DetaultTestExecutionListener could provide stacktrace as part of the 'sync' token (much like mem data), and 
          //      avoid this suspicious check
          outputKind = ProcessOutputTypes.STDERR;
        }
        myState.onTextAvailable(text, outputKind);
      }
    }
  }


  @Override
  public void processNotStarted() {
    // XXX I wonder if I can make use of this event. Besides, there's also processWillTerminate(), is there use for it?
  }

  private void onTestEvent(@NotNull TestEventMessage message) {
    String token = message.getToken();
    TestRawEvent event = message.getEvent();
    switch (token) {
      case TestEventMessage.START_TEST:
        myState.onTestStarted(event);
        break;
      case TestEventMessage.FINISH_TEST:
        myState.onTestFinished(event);
        break;
      case TestEventMessage.FAILURE_TEST_BEGIN:
        myState.onTestFailure(event);
        break;
      case TestEventMessage.START_TESTRUN:
        myState.onTestRunStarted(event);
        break;
      case TestEventMessage.FINISH_TESTRUN:
        myState.onTestRunFinished(event);
        break;
      case TestEventMessage.ASSUMPTION_FAILURE_TEST_PREFIX:
        myState.onTestAssumptionFailure(event);
        break;
      case TestEventMessage.IGNORE_FAILURE_TEST_PREFIX:
        myState.onTestIgnored(event);
    }
  }

  /**
   * FIXME This hack may potentially cause misinterpretation of stream contents.
   */
  private boolean isErrorOutputInProgress() {
    return myLastEvent != null && myLastEvent.isErrored();
  }
}
